/**
 * @name ZipEntry name flows to FileUtils.resolveFile with startsWith check before canonicalization
 * @description ZipEntry name reaches FileUtils.resolveFile where startsWith check precedes getCanonicalFile
 * @kind path-problem
 * @problem.severity error
 * @id java/zipentry-to-resolvefile-traversal
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module ZipResolveConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    exists(MethodCall mc |
      mc.getMethod().hasName("getName") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.util.zip", "ZipEntry") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Sink is the call to FileUtils.resolveFile
    exists(MethodCall mc |
      mc.getMethod().hasName("resolveFile") and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.codehaus.plexus.util", "FileUtils") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // Or direct new File() in resolveFile itself
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      ce.getEnclosingCallable().hasName("resolveFile") and
      ce.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.codehaus.plexus.util", "FileUtils") and
      sink.asExpr() = ce.getAnArgument()
    )
  }
}

module ZipResolveFlow = TaintTracking::Global<ZipResolveConfig>;
import ZipResolveFlow::PathGraph

from ZipResolveFlow::PathNode source, ZipResolveFlow::PathNode sink
where ZipResolveFlow::flowPath(source, sink)
select sink.getNode(), source, sink,
  "ZipEntry name flows to FileUtils.resolveFile - path traversal possible as startsWith check precedes canonicalization."

/**
 * @name Zip Slip - ZipEntry name with no containment check after canonicalization
 * @description Confirms the full Zip Slip path: ZipEntry.getName() -> Expand.extractFile -> FileUtils.resolveFile
 * where startsWith check is done BEFORE getCanonicalFile, enabling directory traversal
 * @kind path-problem
 * @problem.severity error
 * @id java/zip-slip-confirmed
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module ZipSlipConfirmedConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    exists(MethodCall mc |
      mc.getMethod().hasName("getName") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.util.zip", "ZipEntry") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // The File construction inside FileUtils.resolveFile after the startsWith check
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      ce.getEnclosingCallable().hasName("resolveFile") and
      ce.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.codehaus.plexus.util", "FileUtils") and
      sink.asExpr() = ce.getAnArgument()
    )
  }

  // No barrier - we want to confirm there's no effective sanitization
}

module ZipSlipConfirmedFlow = TaintTracking::Global<ZipSlipConfirmedConfig>;
import ZipSlipConfirmedFlow::PathGraph

from ZipSlipConfirmedFlow::PathNode source, ZipSlipConfirmedFlow::PathNode sink
where ZipSlipConfirmedFlow::flowPath(source, sink)
select sink.getNode(), source, sink,
  "Confirmed Zip Slip: ZipEntry.getName() flows to File constructor in FileUtils.resolveFile. " +
  "The startsWith check at line 1381 occurs BEFORE getCanonicalFile at line 1387, " +
  "allowing '../' sequences to bypass directory containment."
